import re
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]
APP = ROOT / "app" / "index.html"
API_BASE = "https://bailing-zhigeng-api.onrender.com"


def replace_once(text, old, new, label):
    if old not in text:
        raise RuntimeError(f"Could not find {label}")
    return text.replace(old, new, 1)


def main():
    html = APP.read_text(encoding="utf-8")

    state_old = "const state={view:'home',category:'全部',query:'',space:'',role:localStorage.getItem('bz_role')||'public',saved:JSON.parse(localStorage.getItem('bz_saved')||'[]'),subscriptions:JSON.parse(localStorage.getItem('bz_subscriptions')||'[\"十五五\",\"投资\",\"PMI\"]'),briefs:JSON.parse(localStorage.getItem('bz_briefs')||'[]')};"
    state_new = f"const API_BASE='{API_BASE}';\n    const apiState={{status:'connecting',message:'正在连接实时后端',updated_at:'',runs:[]}};\n    const state={{view:'home',category:'全部',query:'',space:'',role:localStorage.getItem('bz_role')||'public',saved:JSON.parse(localStorage.getItem('bz_saved')||'[]'),subscriptions:JSON.parse(localStorage.getItem('bz_subscriptions')||'[\"十五五\",\"投资\",\"PMI\"]'),briefs:JSON.parse(localStorage.getItem('bz_briefs')||'[]'),toolResult:null}};"
    html = replace_once(html, state_old, state_new, "state")

    helper_insert = "async function api(path,opts={}){const res=await fetch(API_BASE+path,{headers:{'Content-Type':'application/json'},...opts});if(!res.ok)throw new Error(`${res.status} ${res.statusText}`);return res.json()}\n    async function refreshLiveData(){try{apiState.status='connecting';const [health,items,sources,runs]=await Promise.all([api('/api/health'),api('/api/items?limit=500'),api('/api/sources'),api('/api/runs')]);data.items=items.items||data.items;data.sources=sources.sources||data.sources;data.item_count=data.items.length;apiState.status='live';apiState.message=`实时后端已连接：${health.counts?.items||data.items.length} items / ${health.counts?.sources||data.sources.length} sources`;apiState.updated_at=health.time||'';apiState.runs=runs.runs||[];render()}catch(err){apiState.status='fallback';apiState.message='实时后端暂不可用，正在使用静态快照：'+err.message;render()}}\n    async function runTool(toolId){const out=qs('toolOutput');if(out)out.textContent='正在调用知更实时工作台...';try{let payload;if(toolId==='brief'){payload=await api('/api/briefs/generate',{method:'POST',body:JSON.stringify({title:'知更客户晨报',keywords:state.subscriptions,categories:['产业监管','公司公告','国家政策'],limit:8})});state.toolResult={type:'brief',payload};state.briefs.unshift({created_at:payload.generated_at,title:payload.title,body:payload.summary});state.briefs=state.briefs.slice(0,12);save()}else{payload=await api('/api/impact-matrix',{method:'POST',body:JSON.stringify({topic:state.subscriptions.join('、'),keywords:state.subscriptions,categories:['产业监管','公司公告','国家政策'],limit:8})});state.toolResult={type:'matrix',payload}}renderWorkspace();toast('实时工具已完成','结果来自 Render 后端 API')}catch(err){if(out)out.textContent='调用失败：'+err.message;toast('工具调用失败',err.message)}}\n    "
    html = replace_once(html, "function toast(t,b)", helper_insert + "function toast(t,b)", "helpers")

    hero_new = "function hero(title,sub,eyebrow='BAILING / ZHIGENG'){const counts=categoryCounts(), status=sourceStatusCounts(), latest=data.items.map(i=>i.published_at).sort().pop()||'';return `<section class=\"hero\"><div class=\"hero-copy\"><div class=\"eyebrow\">${esc(eyebrow)}</div><h1>${esc(title)}</h1><p>${esc(sub)}</p><div class=\"stats\"><div><strong>${data.items.length}</strong><span>信息条目</span></div><div><strong>${data.sources.length}</strong><span>已接信源</span></div><div><strong>${esc(latest)}</strong><span>最新日期</span></div></div></div><aside class=\"hero-side\"><div class=\"panel-head\"><h3>运行状态</h3><span>${esc(apiState.status)}</span></div><div class=\"admin-grid\"><div class=\"admin-card\"><header><strong>${Object.keys(counts).length}</strong><em>categories</em></header><p>${esc(apiState.message||'静态快照已加载')}</p></div><div class=\"admin-card\"><header><strong>${status.ok||0}</strong><em>ok</em></header><p>当前可用信源。${apiState.updated_at?' 后端时间 '+esc(apiState.updated_at):''}</p></div></div></aside></section>`}"
    html, n = re.subn(r"function hero\(title,sub,eyebrow='BAILING / ZHIGENG'\).*?(?=\n    function itemCard)", hero_new, html, count=1, flags=re.S)
    if n != 1:
        raise RuntimeError("Could not replace hero")

    workspace_pat = re.compile(r"function renderWorkspace\(\).*?(?=\n    function renderAdmin\(\))", re.S)
    workspace_new = r"""function renderWorkspace(){const verified=state.role==='verified';const result=state.toolResult;let resultHtml='<div class="output" id="toolOutput">选择一个专业工具运行。</div>';if(result&&result.type==='brief'){const lines=(result.payload.items||[]).map(i=>`- ${esc(i.title)}（${esc(i.source_name)}）`).join('\\n');resultHtml=`<div class="output" id="toolOutput"><strong>${esc(result.payload.title)}</strong>\\n${esc(result.payload.summary)}\\n\\n${lines}</div>`}else if(result){const lines=(result.payload.matrix||[]).map(x=>`- [${esc(x.impact_strength)}] ${esc(x.title)}\\n  ${esc(x.consulting_action)}\\n  ${esc(x.url)}`).join('\\n\\n');resultHtml=`<div class="output" id="toolOutput"><strong>政策影响矩阵：${esc(result.payload.topic)}</strong>\\n${lines}</div>`}qs('view-workspace').innerHTML=hero(UI.workspaceTitle,UI.workspaceSub,'ZHIGENG WORKSPACE')+`${!verified?'<div class="panel"><div class="panel-head"><h3>权限提示</h3><span>not verified</span></div><div class="mini-list"><div class="mini-row"><p>你当前还不是知更认证顾问，可以在“认证申请”里切换为认证顾问体验完整工作台。</p></div></div></div>':''}<section class="grid"><div class="panel"><div class="panel-head"><h3>专业工具</h3><span>${verified?'api enabled':'preview'}</span></div><div class="tool-grid">${authPayload.pro_tools.map((t,idx)=>`<article class="tool-card"><header><strong>${esc(t.name)}</strong><em>${verified?'实时API':'认证后'}</em></header><p>${esc(t.description)}</p><div class="actions"><button data-tool="${idx===0?'brief':'matrix'}">${verified?'运行':'查看说明'}</button></div></article>`).join('')}</div></div><aside class="side-stack"><div class="panel"><div class="panel-head"><h3>我的订阅</h3><span>${state.subscriptions.length}</span></div><div class="mini-list">${state.subscriptions.map(s=>`<div class="mini-row"><header><strong>${esc(s)}</strong><em>on</em></header><p>关键词追踪中。</p></div>`).join('')}<div class="actions"><button id="addSub">添加订阅</button></div></div></div></aside></section><section class="grid"><div class="panel"><div class="panel-head"><h3>晨报素材</h3><span>${state.briefs.length}</span></div><div class="feed">${state.briefs.map(b=>`<article class="card"><div class="meta"><span>${esc(b.created_at)}</span></div><a class="title">${esc(b.title)}</a><p>${esc(b.body)}</p></article>`).join('')||'<div class="mini-row"><p>还没有晨报素材。点击专业工具可实时生成。</p></div>'}</div></div><aside class="side-stack"><div class="panel"><div class="panel-head"><h3>收藏夹</h3><span>${state.saved.length}</span></div><div class="mini-list">${state.saved.map(id=>data.items.find(i=>i.id===id)).filter(Boolean).map(i=>`<div class="mini-row"><header><strong>${esc(i.title)}</strong><em>${esc(i.category)}</em></header><p>${esc(i.source_name)}</p></div>`).join('')||'<div class="mini-row"><p>暂无收藏。</p></div>'}</div></div></aside></section><section class="panel"><div class="panel-head"><h3>生成结果</h3><span>${apiState.status}</span></div><div class="feed">${resultHtml}</div></section>`;qs('view-workspace').querySelectorAll('[data-tool]').forEach(b=>b.onclick=()=>verified?runTool(b.dataset.tool):toast('需要认证','请先切换为认证顾问体验完整工作台'));qs('addSub').onclick=()=>{const pool=['外资','财政','能源','价格','制造业','民营经济','新能源','机器人'];const next=pool.find(x=>!state.subscriptions.includes(x))||('专题'+Date.now());state.subscriptions.push(next);save();renderWorkspace()}}
    """
    html, n = workspace_pat.subn(workspace_new, html, count=1)
    if n != 1:
        raise RuntimeError("Could not replace renderWorkspace")

    admin_pat = re.compile(r"function renderAdmin\(\).*?(?=\n    function render\(\))", re.S)
    admin_new = r"""function renderAdmin(){const health=data.sources.reduce((a,s)=>{a[s.status]=(a[s.status]||0)+1;return a},{});qs('view-admin').innerHTML=hero(UI.adminTitle,UI.adminSub,'ADMIN')+`<section class="grid"><div class="panel"><div class="panel-head"><h3>信源运行</h3><span>${data.sources.length} sources</span></div><div class="source-list">${data.sources.map(s=>`<div class="source-row ${esc(s.status)}"><header><strong>${esc(s.name)}</strong><em>${esc(s.status)}</em></header><p>${esc(s.category)} · ${esc(s.items)} 条 · ${esc(s.url)}</p></div>`).join('')}</div></div><aside class="side-stack"><div class="panel"><div class="panel-head"><h3>实时后端</h3><span>${esc(apiState.status)}</span></div><div class="mini-list"><div class="mini-row"><header><strong>${esc(API_BASE)}</strong><em>api</em></header><p>${esc(apiState.message)}</p></div>${apiState.runs.slice(0,3).map(r=>`<div class="mini-row"><header><strong>${esc(r.run_type)} #${esc(r.id)}</strong><em>${esc(r.status)}</em></header><p>${esc(r.started_at)} · ${esc(r.message)}</p></div>`).join('')}</div><div class="actions"><button id="refreshLive">刷新实时数据</button><button id="runCollect">手动采集</button></div></div><div class="panel"><div class="panel-head"><h3>状态统计</h3><span>health</span></div><div class="admin-grid" style="grid-template-columns:1fr">${Object.entries(health).map(([k,v])=>`<div class="admin-card"><header><strong>${esc(k)}</strong><em>${v}</em></header><p>本次采集状态。</p></div>`).join('')}</div></div><div class="panel"><div class="panel-head"><h3>信源版图</h3><span>roadmap</span></div><div class="mini-list">${(data.source_landscape||[]).map(x=>`<div class="mini-row"><header><strong>${esc(x.name)}</strong><em>${esc(x.connected)} / ${esc(x.target)}</em></header><p>${esc(x.note)}；缺口 ${Math.max(0,(x.target||0)-(x.connected||0))} 个。</p></div>`).join('')||'<div class="mini-row"><p>暂无信源版图数据。</p></div>'}</div></div></aside></section>`;qs('refreshLive').onclick=refreshLiveData;qs('runCollect').onclick=async()=>{apiState.message='正在触发后端采集...';renderAdmin();try{await api('/api/collect/run',{method:'POST',body:'{}'});await refreshLiveData();toast('采集完成','后端已重新抓取并刷新数据')}catch(err){apiState.status='error';apiState.message=err.message;renderAdmin();toast('采集失败',err.message)}}}
    """
    html, n = admin_pat.subn(admin_new, html, count=1)
    if n != 1:
        raise RuntimeError("Could not replace renderAdmin")

    html = replace_once(html, "renderNav(); render();", "renderNav(); render(); refreshLiveData();", "boot")
    APP.write_text(html, encoding="utf-8")
    print("Connected frontend to Render API")


if __name__ == "__main__":
    main()

